# Client capabilities (sent during initialize)
{
  "capabilities": {
    "roots": {
      "listChanged": true   # server can receive notifications when roots change
    }
  }
}

# Server calls roots/list
{
  "jsonrpc": "2.0",
  "id": 1,
  "method": "roots/list"
}

# Client responds
{
  "jsonrpc": "2.0",
  "id": 1,
  "result": {
    "roots": [
      {
        "uri": "file:///home/alice/projects/myapp",
        "name": "myapp"
      },
      {
        "uri": "file:///home/alice/docs",
        "name": "Documentation"
      }
    ]
  }
}

# Client → Server notification (no response expected)
{
  "jsonrpc": "2.0",
  "method": "notifications/roots/list_changed"
}
# Server re-calls roots/list to get the updated set

from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp import types
from pathlib import Path

app = Server("workspace-tool")

@app.list_tools()
async def list_tools() -> list[types.Tool]:
    return [
        types.Tool(
            name="find_files",
            description="Find files matching a glob pattern in the workspace",
            inputSchema={
                "type": "object",
                "properties": {
                    "pattern": {"type": "string", "description": "Glob pattern, e.g. '**/*.py'"}
                },
                "required": ["pattern"]
            }
        )
    ]

@app.call_tool()
async def call_tool(name: str, arguments: dict):
    if name != "find_files":
        raise ValueError(f"Unknown tool: {name}")

    ctx = app.request_context
    roots_result = await ctx.session.list_roots()
    roots = roots_result.roots  # list of Root objects with .uri and .name

    pattern = arguments["pattern"]
    matches = []

    for root in roots:
        if not root.uri.startswith("file://"):
            continue  # only handle filesystem roots

        root_path = Path(root.uri.removeprefix("file://"))
        if not root_path.exists():
            continue

        for match in root_path.glob(pattern):
            matches.append(str(match))

    return [types.TextContent(
        type="text",
        text="\n".join(matches) if matches else "No files found."
    )]

async def main():
    async with stdio_server() as (read, write):
        await app.run(read, write, app.create_initialization_options())

import asyncio
asyncio.run(main())

from pathlib import Path
from mcp import types

async def resolve_within_roots(relative_path: str, session) -> Path:
    """Resolve a path and verify it is under a declared root."""
    roots_result = await session.list_roots()
    candidate = Path(relative_path).resolve()

    for root in roots_result.roots:
        if not root.uri.startswith("file://"):
            continue
        root_path = Path(root.uri.removeprefix("file://")).resolve()
        try:
            candidate.relative_to(root_path)
            return candidate  # path is under this root
        except ValueError:
            continue

    raise PermissionError(
        f"Path '{relative_path}' is outside all declared roots."
    )

@app.call_tool()
async def call_tool(name: str, arguments: dict):
    if name == "read_file":
        ctx = app.request_context
        try:
            path = await resolve_within_roots(arguments["path"], ctx.session)
        except PermissionError as e:
            return [types.TextContent(type="text", text=str(e))]

        content = path.read_text()
        return [types.TextContent(type="text", text=content)]

@app.call_tool()
async def call_tool(name: str, arguments: dict):
    ctx = app.request_context
    client_params = ctx.session.client_params
    caps = getattr(client_params, "capabilities", None)
    has_roots = caps is not None and getattr(caps, "roots", None) is not None

    if name == "scan_workspace":
        if not has_roots:
            return [types.TextContent(
                type="text",
                text="No workspace roots declared by the client. "
                     "Open a folder in your host application to set a workspace scope."
            )]

        roots_result = await ctx.session.list_roots()
        root_paths = [r.uri for r in roots_result.roots if r.uri.startswith("file://")]

        return [types.TextContent(
            type="text",
            text=f"Workspace contains {len(root_paths)} root(s):\n" +
                 "\n".join(root_paths)
        )]

@app.list_resources()
async def list_resources() -> list[types.Resource]:
    ctx = app.request_context
    try:
        roots_result = await ctx.session.list_roots()
    except Exception:
        return []  # roots not available, expose nothing

    resources = []
    for root in roots_result.roots:
        if not root.uri.startswith("file://"):
            continue
        root_path = Path(root.uri.removeprefix("file://"))
        for py_file in root_path.rglob("*.py"):
            resources.append(types.Resource(
                uri=f"file://{py_file}",
                name=py_file.name,
                mimeType="text/x-python",
                description=f"Python source file in {root.name}"
            ))

    return resources
